#include<cstdio>
#include<vector>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
typedef long long LL;
inline LL read()
{
	LL res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=3e5+10;int P[N],p,n,m;
struct node
{
	int c,w,d;inline node(const int &C=0,const int &W=0,const int &D=0){c=C;d=D;w=W;}
	inline bool operator < (const node &Q)const{return w<Q.w;}
}q[N];
std::vector<int> OP[N]; struct SEG{int l,r;LL sm,sz;}t[N<<5]; int Rt[N],cnt;
inline int bnd(const int &k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]>=k?l=m+1:r=m-1;return l-1;}
inline void update(const int &x){t[x].sm=t[t[x].l].sm+t[t[x].r].sm;t[x].sz=t[t[x].l].sz+t[t[x].r].sz;}
inline void add(int cur,int &x,const int &pos,const int &l=1,const int &r=n)
{
	
	t[x=++cnt]=t[cur];if(l==r){t[x].sm=1ll*q[pos].w*q[pos].c;t[x].sz=q[pos].c;return;} 
	const int &mid=(l+r)>>1; pos<=mid?add(t[cur].l,t[x].l,pos,l,mid):add(t[cur].r,t[x].r,pos,mid+1,r);update(x);
}
inline LL qry(int cur,const LL &W,const int &l=1,const int &r=n)
{
//	printf("qry %d %lld %d %d\n",cur,W,l,r);
	if(l==r){return min(W/q[l].w,t[cur].sz);} const int &mid=(l+r)>>1;
	if(t[t[cur].l].sm>=W)return qry(t[cur].l,W,l,mid);
	return t[t[cur].l].sz+qry(t[cur].r,W-t[t[cur].l].sm,mid+1,r);
}
inline void debug(const int &cur,const int &l=1,const int &r=n)
{
	if(l==r)return printf("%d ",l),void();int mid=(l+r)>>1;
	if(t[cur].l)debug(t[cur].l,l,mid);if(t[cur].r)debug(t[cur].r,mid+1,r);
}
int main()
{
	
	n=read();m=read();rep(1,n,i)q[i]=node(read(),read(),P[i]=read());std::sort(q+1,q+n+1);
	std::sort(P+1,P+n+1,[&](const int &x,const int &y){return x>y;}); p=std::unique(P+1,P+n+1)-P-1;
	rep(1,n,i)OP[q[i].d=bnd(q[i].d)].push_back(i); P[0]=-1;
	rep(1,p,i){t[Rt[i]=++cnt]=t[Rt[i-1]];for(int v: OP[i])add(Rt[i],Rt[i],v);}
//	rep(1,n,i)printf("%d :: d=%d w=%d c=%d\n",i,q[i].d,q[i].w,q[i].c);
//	rep(1,p,i){printf("debug %d :: ",i);debug(Rt[i]);printf("Rt :: %d\n",Rt[i]);}
//	rep(1,cnt,i)printf("%d :: %d %d %lld %lld\n",i,t[i].l,t[i].r,t[i].sm,t[i].sz);
//	while(1){LL d=read(),w=read();printf("%lld\n",qry(Rt[d],w));}
	while(m--)
	{
		LL W=read(),Q=read();int l(1),r(p),mid,res=0;
		while(l<=r){mid=(l+r)>>1;if(qry(Rt[mid],W)>=Q){res=mid;r=mid-1;}else l=mid+1;}
		printf("%d\n",P[res]);
	}
}
